mapper.select:
SELECT COUNT(*) FROM simple_review 
WHERE SIMPLE_REVIEW_TMDB_MOVIE_ID = #{movieId} 
AND SIMPLE_REVIEW_MEMBER_ID = #{memberId}

mapper.update:
UPDATE simple_review SET
simple_review_rating = #{simpleReviewRating},
simple_review_content = #{simpleReviewContent}
WHERE simple_review_no = #{simpleReviewNo}

mapper.select:
SELECT COUNT(*) 
FROM simple_review 
WHERE simple_review_member_id = #{memberId}

SELECT AVG(simple_review_rating) 
FROM simple_review 
WHERE simple_review_member_id = #{memberId}

SELECT COUNT(*) 
FROM simple_review 
WHERE simple_review_member_id = #{memberId}

SELECT COUNT(DISTINCT sr.simple_review_no)
FROM simple_review sr
INNER JOIN userpick_movie um ON sr.simple_review_tmdb_movie_id = um.userpick_movie_tmdb_movie_id
INNER JOIN userpick_genre ug ON um.userpick_movie_no = ug.userpick_genre_movie_no
WHERE sr.simple_review_member_id = #{memberId}
AND ug.userpick_genre_id = #{genreId}
